sql:
SELECT SUM(quantity) AS total_quantity
FROM order_items
WHERE item_id = 0;

external_knowledge:
- "Current stock" refers to the quantity of items available in the inventory at the time of the query; 
- "Remaining stock" is the quantity of items left after sales; 
- If an item is not found in the current inventory, its remaining stock is considered to be its current stock quantity.

sql:
SELECT
    (SELECT SUM(quantity) FROM inventory) AS total_stock,
    (SELECT COUNT(order_id) FROM orders WHERE order_status = 'delivered' AND order_date >= DATE('now', '-30 days')) AS recent_orders_count;

SELECT DISTINCT c.name
FROM customers c
JOIN orders o ON c.customer_id = o.customer_id;

SELECT AVG(i.quantity) AS avg_quantity
FROM inventory i
JOIN order_items oi ON i.item_id = oi.item_id;

SELECT SUM(quantity) AS total_quantity_sold
FROM order_items
WHERE order_id = 1;
